console.log('Webhook recibido:', { message, sessionId, attachments });
console.log('SessionId generado/usado:', sessionId);

// Preparar datos para el flujo LangChain con sessionId explícito
const messageData = {
  text: message,
  sessionId: sessionId,  // CRÍTICO: sessionId para memoria
  userInput: message,
  timestamp: new Date().toISOString(),
  isCustomer:isCustomer
};

// Devolver solo el JSON con el sessionId correcto
return {
  json: messageData
};
